const defaultSettings = { theme: 'light', showSidebar: true };
const userSettings = { theme: 'dark' };

//  BAD: This mutates the defaultSettings object permanently!
// Object.assign(defaultSettings, userSettings); 

//  GOOD: Pass an empty object as the target to create a brand new object
const finalConfig = Object.assign({}, defaultSettings, userSettings);

console.log(finalConfig); 
// { theme: 'dark', showSidebar: true }
// 'dark' overwrote 'light' because userSettings was further to the right.
